'use client';

import { useEffect, useMemo, useState } from "react";
import Link from "next/link";
import { usePathname, useRouter } from "next/navigation";
import { Avatar, AvatarFallback } from "@/components/ui/avatar";
import { Button } from "@/components/ui/button";
import CustomerProtectedRoute from "@/components/CustomerProtectedRoute";
import { cn } from "@/lib/utils";
import {
  Ban,
  CalendarCheck,
  ChevronRight,
  History,
  LayoutDashboard,
  LogOut,
  Menu,
  Sparkles,
  X,
} from "lucide-react";

const menuItems = [
  {
    icon: CalendarCheck,
    label: "Appointments",
    description: "See all upcoming visits",
    path: "/customer/appointments",
  },
  {
    icon: History,
    label: "Previous Appointments",
    description: "Review completed bookings",
    path: "/customer/appointments/previous",
  },
  {
    icon: Ban,
    label: "Cancelled Appointments",
    description: "See what was called off",
    path: "/customer/appointments/cancelled",
  },
];

function CustomerLayoutShell({ children }: { children: React.ReactNode }) {
  const pathname = usePathname();
  const router = useRouter();
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [customerName, setCustomerName] = useState("Customer");
  const [customerEmail, setCustomerEmail] = useState<string | null>(null);

  useEffect(() => {
    if (typeof window === "undefined") return;

    const storedName = localStorage.getItem("customerName") || "Customer";
    const storedEmail = localStorage.getItem("customerEmail");

    setCustomerName(storedName.replace(/\b\w/g, (char) => char.toUpperCase()));
    setCustomerEmail(storedEmail);
  }, []);

  const activeItemLabel = useMemo(
    () => menuItems.find((item) => item.path === pathname)?.label ?? "Appointments",
    [pathname],
  );

  const handleLogout = () => {
    if (typeof window !== "undefined") {
      localStorage.removeItem("customerAuth");
      localStorage.removeItem("customerEmail");
      localStorage.removeItem("customerName");
    }
    router.push("/login");
  };

  return (
    <div className="min-h-screen bg-muted/30">
      <aside
        className={cn(
          "fixed inset-y-0 left-0 z-40 w-64 transform border-r border-border bg-card shadow-lg transition-transform duration-300",
          sidebarOpen ? "translate-x-0" : "-translate-x-full",
          "md:translate-x-0",
        )}
      >
        <div className="flex h-full flex-col">
          <div className="flex items-center justify-between border-b border-border px-4 py-5">
            <div className="flex items-center gap-3">
              <div className="flex h-10 w-10 items-center justify-center rounded-full bg-primary/10">
                <Sparkles className="h-5 w-5 text-primary" />
              </div>
              <div>
                <p className="text-sm font-semibold text-foreground">Orbit Booking</p>
                <p className="text-xs text-muted-foreground">Customer Portal</p>
              </div>
            </div>
            <Button
              variant="ghost"
              size="icon"
              className="md:hidden"
              onClick={() => setSidebarOpen(false)}
            >
              <X className="h-4 w-4" />
              <span className="sr-only">Close sidebar</span>
            </Button>
          </div>

          <nav className="flex-1 space-y-1 overflow-y-auto px-2 py-4">
            {menuItems.map((item) => {
              const Icon = item.icon;
              const isActive = pathname === item.path;
              return (
                <Link
                  key={item.path}
                  href={item.path}
                  onClick={() => setSidebarOpen(false)}
                  className={cn(
                    "group flex items-center gap-3 rounded-xl px-3 py-3 transition-all",
                    isActive
                      ? "text-white shadow-lg"
                      : "text-muted-foreground hover:bg-muted hover:text-foreground",
                  )}
                  style={
                    isActive
                      ? { background: "linear-gradient(135deg, #00BCD4 0%, #00D4E8 100%)" }
                      : undefined
                  }
                >
                  <Icon className="h-5 w-5 flex-shrink-0" />
                  <div className="flex-1 text-sm">
                    <p className="font-medium">{item.label}</p>
                    <p className="text-xs text-muted-foreground group-hover:text-muted-foreground/90">
                      {item.description}
                    </p>
                  </div>
                  <ChevronRight className="h-4 w-4 opacity-0 transition-opacity group-hover:opacity-100" />
                </Link>
              );
            })}
          </nav>

          <div className="border-t border-border px-4 py-4">
            <div className="flex items-center gap-3">
              <Avatar className="h-9 w-9">
                <AvatarFallback>{customerName.charAt(0).toUpperCase()}</AvatarFallback>
              </Avatar>
              <div className="flex-1">
                <p className="text-sm font-medium text-foreground">{customerName}</p>
                <p className="text-xs text-muted-foreground truncate">{customerEmail ?? "—"}</p>
              </div>
            </div>
            <Button variant="destructive" className="mt-4 w-full" onClick={handleLogout}>
              <LogOut className="mr-2 h-4 w-4" /> Sign Out
            </Button>
          </div>
        </div>
      </aside>

      {sidebarOpen && (
        <div
          className="fixed inset-0 z-30 bg-black/40 backdrop-blur-sm md:hidden"
          onClick={() => setSidebarOpen(false)}
        />
      )}

      <div className="min-h-screen transition-[margin-left] duration-300 md:ml-64">
        <header className="sticky top-0 z-30 border-b border-border bg-background/80 backdrop-blur">
          <div className="flex items-center justify-between gap-4 px-4 py-4 md:px-8">
            <div className="flex items-center gap-3">
              <Button
                variant="ghost"
                size="icon"
                className="md:hidden"
                onClick={() => setSidebarOpen(true)}
              >
                <Menu className="h-5 w-5" />
                <span className="sr-only">Open sidebar</span>
              </Button>
              <div>
                <p className="text-xs uppercase tracking-wide text-muted-foreground">{activeItemLabel}</p>
                <h1 className="text-xl font-semibold text-foreground">Welcome back, {customerName}</h1>
              </div>
            </div>
          </div>
        </header>
        <main className="px-4 py-6 md:px-8 md:py-8">{children}</main>
      </div>
    </div>
  );
}

export default function CustomerLayout({ children }: { children: React.ReactNode }) {
  return (
    <CustomerProtectedRoute>
      <CustomerLayoutShell>{children}</CustomerLayoutShell>
    </CustomerProtectedRoute>
  );
}
